// Parse document metadata from the HTTP response
const data = $input.first().json;

// Extract page count
const pageCount = data.pageCount || data.pages || 1;

// Detect color vs B&W
const isColor = data.colorPages > 0 || data.hasColor || false;

// Determine paper size
const paperSize = data.paperSize || 'A4';

// Calculate base price estimate (INR)
const pricePerPageBW = 1.5;
const pricePerPageColor = 8;
const estimatedPrice = isColor
  ? pageCount * pricePerPageColor
  : pageCount * pricePerPageBW;

// Get user info from original webhook payload
const userLat   = $('1. Webhook Trigger').first().json.body.lat;
const userLng   = $('1. Webhook Trigger').first().json.body.lng;
const userName  = $('1. Webhook Trigger').first().json.body.name;
const userPhone = $('1. Webhook Trigger').first().json.body.phone;
const fileName  = $('1. Webhook Trigger').first().json.body.filename;

return [{
  json: {
    pageCount,
    isColor,
    paperSize,
    estimatedPrice,
    userLat,
    userLng,
    userName,
    userPhone,
    fileName
  }
}];

